<?php
namespace App\Services\Security;use App\Models\{SecurityIncident,SecurityIncidentCorrectiveAction,SecurityIncidentPostmortem,User};use Illuminate\Validation\ValidationException;
class SecurityIncidentPostmortemService{public function createDraft(SecurityIncident $i,User $a):SecurityIncidentPostmortem{$p=$i->postmortems()->create(['status'=>'draft','prepared_by_id'=>$a->id]);$this->event($p,$a,'created','Postmortem draft created.');return $p;}public function updateDraft(SecurityIncidentPostmortem $p,User $a,array $d):SecurityIncidentPostmortem{$p->update(collect($d)->only(['summary','root_cause','impact_summary','detection_summary','response_summary','prevention_summary','lessons_learned'])->all());$this->event($p,$a,'updated','Postmortem draft updated.');return $p->refresh();}public function submit(SecurityIncidentPostmortem $p,User $a):SecurityIncidentPostmortem{$missing=collect(['summary','root_cause','impact_summary','response_summary','prevention_summary'])->filter(fn($f)=>blank($p->$f))->all();if($missing)throw ValidationException::withMessages(['postmortem'=>'Required RCA fields are missing: '.implode(', ',$missing)]);$p->update(['status'=>'submitted','submitted_at'=>now()]);$this->event($p,$a,'submitted','Postmortem submitted for approval.');return $p->refresh();}public function approve(SecurityIncidentPostmortem $p,User $a,string $note):SecurityIncidentPostmortem{if(trim($note)==='')throw ValidationException::withMessages(['note'=>'Postmortem approval note is required.']);if(!$a->can('admin.security.incident_postmortems.approve'))throw ValidationException::withMessages(['permission'=>'Postmortem approval permission is required.']);$p->update(['status'=>'approved','approved_by_id'=>$a->id,'approved_at'=>now()]);SecurityIncident::find($p->security_incident_id)->update(['postmortem_completed_at'=>now()]);$this->event($p,$a,'approved',$note);return $p->refresh();}public function reject(SecurityIncidentPostmortem $p,User $a,string $reason):SecurityIncidentPostmortem{$p->update(['status'=>'rejected','rejected_by_id'=>$a->id,'rejected_at'=>now(),'rejection_reason'=>$reason]);$this->event($p,$a,'rejected',$reason);return $p->refresh();}public function addCorrectiveAction(SecurityIncident $i,User $a,array $d):SecurityIncidentCorrectiveAction{$x=$i->correctiveActions()->create($d);$this->incidentEvent($i,$a,'corrective_action_added',"Corrective action added: {$x->title}");return $x;}public function completeCorrectiveAction(SecurityIncidentCorrectiveAction $x,User $a,string $note):SecurityIncidentCorrectiveAction{$x->update(['status'=>'completed','completed_by_id'=>$a->id,'completed_at'=>now(),'completion_note'=>$note]);$this->incidentEvent(SecurityIncident::find($x->security_incident_id),$a,'corrective_action_completed',$note);return $x->refresh();}public function blockCorrectiveAction(SecurityIncidentCorrectiveAction $x,User $a,string $reason):SecurityIncidentCorrectiveAction{$x->update(['status'=>'blocked','blocked_reason'=>$reason]);$this->incidentEvent(SecurityIncident::find($x->security_incident_id),$a,'corrective_action_blocked',$reason);return $x->refresh();}private function event($p,$a,$t,$d){$p->events()->create(['security_incident_id'=>$p->security_incident_id,'actor_id'=>$a->id,'event_type'=>$t,'description'=>$d,'created_at'=>now()]);$this->incidentEvent(SecurityIncident::find($p->security_incident_id),$a,"postmortem_{$t}",$d);}private function incidentEvent($i,$a,$t,$d){$i->events()->create(['actor_id'=>$a->id,'event_type'=>$t,'description'=>$d,'created_at'=>now()]);}}
